def schedule(pending, gpus, now, params):
    headroom = params.get('headroom', 0.5)
    admissions = {g.gpu_id: [] for g in gpus}

    # Sort pending by waiting time (FCFS)
    sorted_pending = sorted(pending, key=lambda x: x.waiting_since)

    for req in sorted_pending:
        # Find GPU with most free space that satisfies headroom
        best_gpu = None
        max_free = -1

        for g in gpus:
            if g.num_active < g.max_batch:
                # Calculate effective free blocks after headroom
                reserved = int(g.blocks_total * headroom)
                effective_free = g.free_blocks - reserved

                # Need at least prefill blocks to start
                if effective_free >= req.prefill_tokens // 16:
                    if g.free_blocks > max_free:
                        max_free = g.free_blocks
                        best_gpu = g

        if best_gpu:
            admissions[best_gpu.gpu_id].append(req.rid)
            best_gpu.free_blocks -= (req.prefill_tokens // 16)
            best_gpu.num_active += 1

    return admissions

